import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useLocation,
} from "react-router-dom";
import Cookies from "js-cookie";
import { useState, useEffect } from "react";
import axios from "axios";

import PermissionContext from "./context/PermissionContext";
import ProtectedRoute from "./components/ProtectedRoute";

import AdminLogin from "./pages/AdminLogin";
import Dashboard from "./pages/Dashboard";
import MyProfile from "./pages/MyProfile";
import UserManagement from "./pages/UserManagement";
import PaymentsManagement from "./pages/PaymentsManagement";
import EmployeeManagement from "./pages/EmployeeManagement";
import UserDetails from "./pages/UserDetails";
import SupportManagement from "./pages/SupportManagement";
import RoleManagement from "./pages/RoleManagement";
import PermissionManagement from "./pages/PermissionManagement";
import ProtectedLayout from "./layouts/ProtectedLayout";

const API_BASE_URL = process.env.REACT_APP_API_BASE_URL;

function App() {
  const [permissions, setPermissions] = useState([]);
  const [isAuthenticated, setIsAuthenticated] = useState(!!Cookies.get("adminToken"));
  const [loadingUser, setLoadingUser] = useState(true); // 🔥 track user fetch

  // Scroll to top on route change
  function ScrollToTop() {
    const { pathname } = useLocation();
    useEffect(() => window.scrollTo(0, 0), [pathname]);
    return null;
  }

  // Fetch current user and permissions
  const fetchCurrentUser = async () => {
    const token = Cookies.get("adminToken");
    if (!token) {
      setIsAuthenticated(false);
      setLoadingUser(false);
      return;
    }

    try {
      const res = await axios.get(`${API_BASE_URL}/admin/me`, {
        headers: { Authorization: `Bearer ${token}` },
      });

      if (res.data.status) {
        setPermissions(res.data.user.permissions || []);
        setIsAuthenticated(true);
        localStorage.setItem("user", JSON.stringify(res.data.user)); // minimal info for role
      } else {
        setIsAuthenticated(false);
      }
    } catch (err) {
      console.error("Error fetching user:", err);
      setIsAuthenticated(false);
    } finally {
      setLoadingUser(false);
    }
  };

  useEffect(() => {
    fetchCurrentUser();
  }, []);

  // Optional: refresh permissions every 5 minutes
  useEffect(() => {
    const interval = setInterval(fetchCurrentUser, 5 * 60 * 1000);
    return () => clearInterval(interval);
  }, []);

  return (
    <PermissionContext.Provider value={{ permissions, setPermissions }}>
      <BrowserRouter>
        <ScrollToTop />

        <Routes>
          {/* Login */}
          <Route
            path="/"
            element={
              <AdminLogin
                setAuth={setIsAuthenticated}
                setPermissions={setPermissions}
              />
            }
          />

          {/* Protected Routes */}
          <Route element={<ProtectedLayout />}>
            <Route
              path="/dashboard"
              element={
                <ProtectedRoute loadingUser={loadingUser}>
                  <Dashboard />
                </ProtectedRoute>
              }
            />

            <Route
              path="/myprofile"
              element={
                <ProtectedRoute loadingUser={loadingUser}>
                  <MyProfile />
                </ProtectedRoute>
              }
            />

            <Route
              path="/users"
              element={
                <ProtectedRoute requiredPermission="viewUser" loadingUser={loadingUser}>
                  <UserManagement />
                </ProtectedRoute>
              }
            />

            <Route
              path="/users/:userId"
              element={
                <ProtectedRoute requiredPermission="viewUser" loadingUser={loadingUser}>
                  <UserDetails />
                </ProtectedRoute>
              }
            />

            <Route
              path="/payment"
              element={
                <ProtectedRoute requiredPermission="viewPayment" loadingUser={loadingUser}>
                  <PaymentsManagement />
                </ProtectedRoute>
              }
            />

            <Route
              path="/support"
              element={
                <ProtectedRoute requiredPermission="viewSupport" loadingUser={loadingUser}>
                  <SupportManagement />
                </ProtectedRoute>
              }
            />

            <Route
              path="/employee"
              element={
                <ProtectedRoute requiredPermission="viewEmployee" loadingUser={loadingUser}>
                  <EmployeeManagement />
                </ProtectedRoute>
              }
            />

            <Route
              path="/roles"
              element={
                <ProtectedRoute adminOnly loadingUser={loadingUser}>
                  <RoleManagement />
                </ProtectedRoute>
              }
            />

            <Route
              path="/permissions"
              element={
                <ProtectedRoute adminOnly loadingUser={loadingUser}>
                  <PermissionManagement />
                </ProtectedRoute>
              }
            />
          </Route>

          {/* 404 */}
          <Route path="*" element={<div>404 - Page not found</div>} />
        </Routes>
      </BrowserRouter>
    </PermissionContext.Provider>
  );
}

export default App;
